import './style.css';
import { Map, Overlay, View } from 'ol';
import { Tile as TileLayer, Vector as VectorLayer, Heatmap as HeatmapLayer } from 'ol/layer';
import { XYZ as XYZSource, Vector as VectorSource } from 'ol/source';
import { Style, Icon, Text, Fill, Stroke } from 'ol/style';
import { GeoJSON, KML } from 'ol/format';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { fromLonLat, toLonLat } from 'ol/proj';
import { toRadians } from 'ol/math';
import { toStringHDMS } from 'ol/coordinate';
import { defaults as defaultControls, ScaleLine, Control } from 'ol/control';

const myApi = '14d683ff9d8989c5c7c5ebd386ac6577';

const baseLayer = new TileLayer({
  source: new XYZSource({
    url: 'http://t6.tianditu.com/DataServer?T=vec_w&x={x}&y={y}&l={z}&tk=' + myApi,
  })
});

const satelliteLayer = new TileLayer({
  source: new XYZSource({
    url: 'http://t6.tianditu.com/DataServer?T=img_w&x={x}&y={y}&l={z}&tk=' + myApi,
  })
});

const textLayer = new TileLayer({
  source: new XYZSource({
    url: 'http://t6.tianditu.com/DataServer?T=cva_w&x={x}&y={y}&l={z}&tk=' + myApi,
  })
});

const chinaLayer = new VectorLayer({
  source: new VectorSource({
    format: new GeoJSON,
    url: './json/中华人民共和国.json',
  }),
  style: new Style({
    fill: new Fill({
      color: 'rgba(255, 0, 0, 0.2)' // 红色半透明填充
    }),
    stroke: new Stroke({
      color: 'red', // 红色边界线
      width: 2,
    }),
  })
});

const container = document.getElementById('popup');
const content = document.getElementById('popup-content');
const closer = document.getElementById('popup-closer');

const overlay = new Overlay({
  element: container,
  autoPan: {
    animation: {
      duration: 250,
    },
  },
});

closer.onclick = function () {
  overlay.setPosition(undefined);
  closer.blur();
  return false;
};

const radius = document.getElementById('radius');
const blur = document.getElementById('blur');

const earthquakesHeatmapLayer = new HeatmapLayer({
  source: new VectorSource({
    url: './kml/2012_Earthquakes_Mag5.kml',
    format: new KML({
      extractStyles: false
    })
  }),
  blur: parseFloat(blur.value, 10),
  radius: parseInt(radius.value, 10),
  weight: function (feature) {
    const name = feature.get('name');
    const magnitude = parseFloat(name.substr(2));
    return magnitude - 5;
  }
});

radius.addEventListener('input', function () {
  earthquakesHeatmapLayer.setRadius(parseInt(radius.value, 10));
});
blur.addEventListener('input', function () {
  earthquakesHeatmapLayer.setBlur(parseInt(blur.value, 10));
});


const view1 = new View({
  center: fromLonLat([0, 0]),
  zoom: 2,
  projection: 'EPSG:3857',
  rotation: 0
});

const map = new Map({
  target: 'map',
  layers: [baseLayer, satelliteLayer, chinaLayer, earthquakesHeatmapLayer],
  overlays: [overlay],
  view: view1,
  controls: defaultControls().extend([
    new ScaleLine(),
  ]),
});

map.on('singleclick', function (evt) {
  const coordinate = evt.coordinate;
  const hdms = toStringHDMS(toLonLat(coordinate));

  content.innerHTML = '<p>You clicked here:</p><code>' + hdms + '</code>';
  overlay.setPosition(coordinate);
});

