window.SwitchLayer = function () {
  const layers = map.getLayers().getArray();
  const baseIndex = layers.indexOf(baseLayer);
  const satelliteIndex = layers.indexOf(satelliteLayer);

  layers[baseIndex] = satelliteLayer;
  layers[satelliteIndex] = baseLayer;

  let temp = layers.slice();
  map.setLayers(temp);
};

window.LocatingUser = function () {
  if (navigator.geolocation) {
    navigator.geolocation.getCurrentPosition(function (position) {
      const latitude = position.coords.latitude;
      const longitude = position.coords.longitude;

      view1.setCenter(fromLonLat([longitude, latitude]));
      view1.setZoom(18);
    }, function (error) {
      console.error('Error getting user location:', error);
    });
  } else {
    console.error('Geolocation is not supported by this browser.');
  }
};

window.ClockwiseRotateMap = function () {
  let currentRotation = view1.getRotation();
  let newRotation = currentRotation + toRadians(45);
  view1.setRotation(newRotation);
}

window.CounterclockwiseRotateMap = function () {
  let currentRotation = view1.getRotation();
  let newRotation = currentRotation + toRadians(-45);
  view1.setRotation(newRotation);
}

window.ToDestination = function (coordinates) {
  view1.animate({
    center: fromLonLat(coordinates),
    zoom: 10,
    duration: 1500,
  })
}